import { describe, expect, it } from 'vitest';

import {
  buleyCostAlgebra,
  buleyFaceUnit,
  composeHom,
  composeWithFaceUnit,
  idHom,
  natCostAlgebra,
  scoreHom,
  validateCostHom,
} from '../src/cost-algebra';
import {
  buleHotReplicaAdmission,
  clonedPairScore,
  correctiveContractsForReplica,
  diagonal,
  entropyGeneratedByCloning,
  hotReplicaAdmission,
  isDiagonalScorePreserving,
  replicaTotalHeat,
  replicationEntropy,
} from '../src/cost-algebra-entropy';
import {
  TOWER_CEILINGS,
  clinamenLift,
  vacuumBuleyProjection,
  type BuleyProjection,
} from '../src/spectral-noise-monitor';

const buleSamples: BuleyProjection[] = [
  vacuumBuleyProjection,
  { waste: 1, opportunity: 0, diversity: 0, score: 1 },
  { waste: 2, opportunity: 3, diversity: 0, score: 5 },
  { waste: 0, opportunity: 0, diversity: 4, score: 4 },
  { waste: 6, opportunity: 0, diversity: 0, score: 6 }, // hexon edge
  { waste: 18, opportunity: 0, diversity: 0, score: 18 }, // trihexon
];

describe('CostAlgebra: Bule unit instance', () => {
  it('zero is a left and right identity for compose', () => {
    for (const b of buleSamples) {
      expect(buleyCostAlgebra.compose(buleyCostAlgebra.zero, b)).toEqual(b);
      expect(buleyCostAlgebra.compose(b, buleyCostAlgebra.zero)).toEqual(b);
    }
  });

  it('compose is associative on Bule samples', () => {
    const a = buleSamples[1]!;
    const b = buleSamples[2]!;
    const c = buleSamples[3]!;
    const left = buleyCostAlgebra.compose(buleyCostAlgebra.compose(a, b), c);
    const right = buleyCostAlgebra.compose(a, buleyCostAlgebra.compose(b, c));
    expect(left).toEqual(right);
  });

  it('compose is commutative on Bule samples', () => {
    const a = buleSamples[1]!;
    const b = buleSamples[2]!;
    expect(buleyCostAlgebra.compose(a, b)).toEqual(buleyCostAlgebra.compose(b, a));
  });

  it('score is a monoid homomorphism: score (a · b) = score a + score b', () => {
    for (const a of buleSamples) {
      for (const b of buleSamples) {
        const composedScore = buleyCostAlgebra.score(buleyCostAlgebra.compose(a, b));
        expect(composedScore).toBe(buleyCostAlgebra.score(a) + buleyCostAlgebra.score(b));
      }
    }
  });

  it('vacuum has zero score', () => {
    expect(buleyCostAlgebra.score(buleyCostAlgebra.zero)).toBe(0);
  });
});

describe('CostHom: identity, score, composition', () => {
  it('idHom is the identity on every sample', () => {
    const id = idHom(buleyCostAlgebra);
    for (const b of buleSamples) {
      expect(id.map(b)).toEqual(b);
    }
  });

  it('scoreHom maps every Bule sample to its score', () => {
    const f = scoreHom(buleyCostAlgebra);
    for (const b of buleSamples) {
      expect(f.map(b)).toBe(b.score);
    }
  });

  it('composeHom composes idHom with scoreHom and yields scoreHom', () => {
    const left = composeHom(idHom(buleyCostAlgebra), scoreHom(buleyCostAlgebra));
    for (const b of buleSamples) {
      expect(left.map(b)).toBe(buleyCostAlgebra.score(b));
    }
  });

  it('validateCostHom finds no failures for scoreHom', () => {
    const f = scoreHom(buleyCostAlgebra);
    const failures = validateCostHom(f.map, buleyCostAlgebra, natCostAlgebra, buleSamples);
    expect(failures).toEqual([]);
  });

  it('validateCostHom rejects fst-projection (categorical no-cloning shape)', () => {
    // Pretend "extract waste only" is a candidate hom into natCostAlgebra
    // It preserves zero and compose, but DOES NOT preserve score in general.
    const wasteOnly = (b: BuleyProjection) => b.waste;
    const failures = validateCostHom(wasteOnly, buleyCostAlgebra, natCostAlgebra, buleSamples);
    expect(failures.length).toBeGreaterThan(0);
    expect(failures.some((f) => f.startsWith('preserve_score'))).toBe(true);
  });

  it('buleyFaceUnit gives a unit-score element on every face', () => {
    expect(buleyFaceUnit('waste').score).toBe(1);
    expect(buleyFaceUnit('opportunity').score).toBe(1);
    expect(buleyFaceUnit('diversity').score).toBe(1);
  });

  it('composeWithFaceUnit equals clinamenLift', () => {
    const b: BuleyProjection = { waste: 2, opportunity: 1, diversity: 0, score: 3 };
    expect(composeWithFaceUnit(b, 'waste')).toEqual(clinamenLift(b, 'waste'));
    expect(composeWithFaceUnit(b, 'opportunity')).toEqual(clinamenLift(b, 'opportunity'));
    expect(composeWithFaceUnit(b, 'diversity')).toEqual(clinamenLift(b, 'diversity'));
  });
});

describe('CostAlgebraEntropy: cloning generates exactly source-score of entropy', () => {
  it('vacuum is the only state where the diagonal is score-preserving', () => {
    expect(isDiagonalScorePreserving(buleyCostAlgebra, vacuumBuleyProjection)).toBe(true);
    for (const b of buleSamples.slice(1)) {
      expect(isDiagonalScorePreserving(buleyCostAlgebra, b)).toBe(false);
    }
  });

  it('cloning a state generates exactly score(state) of entropy', () => {
    for (const b of buleSamples) {
      expect(entropyGeneratedByCloning(buleyCostAlgebra, b)).toBe(b.score);
    }
  });

  it('cloned-pair score equals 2 · source score', () => {
    for (const b of buleSamples) {
      expect(clonedPairScore(buleyCostAlgebra, b)).toBe(2 * b.score);
    }
  });

  it('diagonal returns the (s, s) tuple', () => {
    const b = buleSamples[2]!;
    expect(diagonal(b)).toEqual([b, b]);
  });

  it('replicationEntropy: (k - 1) · score for k ≥ 1', () => {
    const b: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
    expect(replicationEntropy(buleyCostAlgebra, b, 0)).toBe(0);
    expect(replicationEntropy(buleyCostAlgebra, b, 1)).toBe(0);
    expect(replicationEntropy(buleyCostAlgebra, b, 2)).toBe(6);
    expect(replicationEntropy(buleyCostAlgebra, b, 3)).toBe(12);
    expect(replicationEntropy(buleyCostAlgebra, b, 4)).toBe(18);
  });

  it('replicaTotalHeat: k · score for k ≥ 1', () => {
    const b: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
    expect(replicaTotalHeat(buleyCostAlgebra, b, 1)).toBe(6);
    expect(replicaTotalHeat(buleyCostAlgebra, b, 2)).toBe(12);
    expect(replicaTotalHeat(buleyCostAlgebra, b, 3)).toBe(18);
  });
});

describe('Hot-Replica admission: Landauer ceiling enforcement', () => {
  it('admits a Hexon-pressure state replicating to 2 nodes at ceiling 12', () => {
    const b: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
    const decision = buleHotReplicaAdmission(b, 2, 12);
    expect(decision.admitted).toBe(true);
    expect(decision.totalHeat).toBe(12);
    expect(decision.deficit).toBe(0);
  });

  it('rejects a Trihexon-pressure state replicating to 2 nodes at Hexon ceiling 6', () => {
    const b: BuleyProjection = { waste: 18, opportunity: 0, diversity: 0, score: 18 };
    const decision = buleHotReplicaAdmission(b, 2, TOWER_CEILINGS.hexon);
    expect(decision.admitted).toBe(false);
    expect(decision.totalHeat).toBe(36);
    expect(decision.deficit).toBe(30);
  });

  it('vacuum is always admitted regardless of replica count', () => {
    for (const k of [1, 2, 5, 10, 100]) {
      const decision = buleHotReplicaAdmission(vacuumBuleyProjection, k, 0);
      expect(decision.admitted).toBe(true);
      expect(decision.totalHeat).toBe(0);
    }
  });

  it('correctiveContractsForReplica computes the right cooling count', () => {
    const b: BuleyProjection = { waste: 18, opportunity: 0, diversity: 0, score: 18 };
    // To replicate to 2 nodes under ceiling 6, source must drop to ≤ 3.
    expect(correctiveContractsForReplica(buleyCostAlgebra, b, 2, 6)).toBe(15);
    // To replicate to 3 nodes under ceiling 6, source must drop to ≤ 2.
    expect(correctiveContractsForReplica(buleyCostAlgebra, b, 3, 6)).toBe(16);
  });

  it('correctiveContracts returns 0 when already admitted', () => {
    const b: BuleyProjection = { waste: 1, opportunity: 0, diversity: 0, score: 1 };
    expect(correctiveContractsForReplica(buleyCostAlgebra, b, 2, 6)).toBe(0);
  });

  it('hotReplicaAdmission works on the natCostAlgebra (Nat-score case)', () => {
    const decision = hotReplicaAdmission(natCostAlgebra, 5, 3, 12);
    expect(decision.totalHeat).toBe(15);
    expect(decision.admitted).toBe(false);
    expect(decision.deficit).toBe(3);
  });
});
